#include <stdio.h>
#include <string.h>
#define MAXN 5
#define MAXM 1000
#define MAXS 100
int T, N, M;
char states[MAXM][MAXN];
int main() {
    scanf("%d", &T);
    while (T--) {
        scanf("%d %d", &N, &M);
        for (int i = 0; i < M; i++) {
            scanf("%s", states[i]);
        }
        // Generate all possible subsets and their states
        int min_size = MAXM * MAXN;
        for (int mask = 0; mask < (1 << N); mask++) {
            int size = 0;
            for (int i = 0; i < N; i++) {
                if ((mask & (1 << i)) != 0) {
                    size++;
                }
            }
            // Check if the subset is present in all parties
            int valid = 1;
            for (int j = 0; j < M; j++) {
                int found = 0;
                for (int i = 0; i < N; i++) {
                    if ((mask & (1 << i)) != 0 && states[j][i] != '0') {
                        found = 1;
                        break;
                    }
                }
                if (!found) {
                    valid = 0;
                    break;
                }
            }
            if (valid) {
                min_size = size;
            }
        }
        printf("%d\n", min_size);
    }
    return 0;
}

