            for (int mask = 0; mask < (1 << N); mask++) {
                int size = 0;
                for (int i = 0; i < N; i++) {
                    if ((mask & (1 << i)) != 0) {
                        size++;
                    }
                }
                // Check if the subset is present in all parties
                boolean valid = true;
                for (int j = 0; j < M; j++) {
                    boolean found = false;
                    for (int i = 0; i < N; i++) {
